		public ExperimentDataViewCell (IntPtr handle) : base (handle)
		{
            DataManager.ResultLinkedExperimentHighlightDidChange += ResultHighlightChanged;
            DataManager.AnalysisResultSelected += DataManager_AnalysisResultSelected;
            DataManager.UpdateViewCells += DataManager_UpdateViewCells;
        }

        private void DataManager_UpdateViewCells(object sender, EventArgs e)
        {
            if (data == null) return;

            NSApplication.SharedApplication.InvokeOnMainThread(() =>
            {
                SetIncludeButtonImage();

                ShowFitDataButton.Enabled = data.Solution != null;
                SetSelectedSolutionHighlighting(DataManager.SelectedSolutionExperimentHighlight);
                NeedsDisplay = true;
            });
        }

        void SetIncludeButtonImage()
        {
            if (data == null) return;

            IncludeDataButton.State = NSCellStateValue.Off;

            if (data.Processor != null && data.Processor.IntegrationCompleted)
            {
                IncludeDataButton.Enabled = true;

                IncludeDataButton.Image = data.Include
                    ? SideBarViewController.DataEnabledImage
                    : SideBarViewController.DataDisabledImage;
            }
            else
            {
                IncludeDataButton.Enabled = false;

                IncludeDataButton.Image = SideBarViewController.DataNotProcessedImage;
            }

            // The recessed control is momentary; only the bezel should change while clicked.
            IncludeDataButton.AlternateImage = IncludeDataButton.Image;
        }

        public override void Layout()
        {
            base.Layout();

            //IncludeDataButton.Image = SideBarViewController.DataDisabledImage;
            //IncludeDataButton.AlternateImage = SideBarViewController.DataEnabledImage;
        }

        private void DataManager_AnalysisResultSelected(object sender, AnalysisResult e)
        {
			NeedsDisplay = true;
        }

		public void Setup(ExperimentData data, Action<ITCDataContainer> removeRequested)
		{
			if (this.data != null)
			{
				this.data.SolutionChanged -= Data_SolutionChanged;
				this.data.ProcessingUpdated -= Data_ProcessingCompleted;
			}

			this.data = data;
			this.removeRequested = removeRequested;

			ExpNameLabel.StringValue = data.Name;
			Line2.StringValue = data.UIShortDateWithTime;
            Line3.LineBreakMode = NSLineBreakMode.TruncatingTail;
            Line3.Cell.LineBreakMode = NSLineBreakMode.TruncatingTail;

            var line3Text = data.MeasuredTemperature.ToString("G3") + " °C | " + data.SyringeConcentration.AsFormattedConcentration(true) + " | " + data.CellConcentration.AsFormattedConcentration(true);
            var line3Attributed = AnalysisITC.UI.MacOS.MacStrings.FromMarkDownString(line3Text, Line3.Font);
            Line3.AttributedStringValue = WithTruncatingLineBreaks(line3Attributed);

            data.SolutionChanged += Data_SolutionChanged;
            data.ProcessingUpdated += Data_ProcessingCompleted;

			ShowFitDataButton.Enabled = data.Solution != null;

			Data_ProcessingCompleted(null, null);

			Data_SolutionChanged(null, null);
        }

        NSAttributedString WithTruncatingLineBreaks(NSAttributedString attributedString)
        {
            var mutable = new NSMutableAttributedString(attributedString);
            var range = new NSRange(0, mutable.Length);
            var paragraph = new NSMutableParagraphStyle
            {
                LineBreakMode = NSLineBreakMode.TruncatingTail,
            };

            mutable.AddAttribute(NSStringAttributeKey.ParagraphStyle, paragraph, range);

            return mutable;
        }

        private void Data_ProcessingCompleted(object sender, EventArgs e)
        {
            var eventData = sender as ExperimentData ?? data;

            NSApplication.SharedApplication.InvokeOnMainThread(() =>
            {
                if (eventData == null || !ReferenceEquals(data, eventData)) return;

                SetIncludeButtonImage();
                SetValidSolutionLabeling();

                LayoutSubtreeIfNeeded();
            });
        }

        private void Data_SolutionChanged(object sender, EventArgs e)
        {
            var eventData = sender as ExperimentData ?? data;

            NSApplication.SharedApplication.InvokeOnMainThread(() =>
            {
                if (eventData == null || !ReferenceEquals(data, eventData)) return;

                if (eventData.Solution != null)
                {
                    SetValidSolutionLabeling();

                    ModelFitLine.UsesSingleLineMode = false;

                    var line = new NSMutableAttributedString("");

                    foreach (var par in eventData.Solution.UISolutionParameters(FinalFigureDisplayParameters.ListView))
                    {
                        // First line is model line, treat special
                        if (line.Length == 0)
                        {
                            line.Append(AnalysisITC.UI.MacOS.MacStrings.FromMarkDownString($"{par.Item1} | RMSD = {par.Item2}", ModelFitLine.Font));
                        }
                        else
                        {
                            line.Append(AnalysisITC.UI.MacOS.MacStrings.FromMarkDownString(Environment.NewLine + par.Item1 + " = ", ModelFitLine.Font));
                            line.Append(AnalysisITC.UI.MacOS.MacStrings.FromMarkDownString(par.Item2, ModelFitLine.Font));
                        }                      
                    }

                    ModelFitLine.AttributedStringValue = line;
                }
                else
                {
                    IsDetailedViewOpen = false;
                    UpdateFitLineVisibility();
                }

                ShowFitDataButton.Enabled = eventData.Solution != null;

                LayoutSubtreeIfNeeded();
            });
        }

        partial void RemoveClick(NSObject obj)
        {
            if (data == null) return;

            removeRequested?.Invoke(data);
        }

        partial void ShowFitDataButtonClick(NSObject sender)
        {
			IsDetailedViewOpen = !IsDetailedViewOpen;

			UpdateFitLineVisibility();
